+    let has_fp = decision
+        .blockers
+        .iter()
+        .any(|b| b.contains("false positives"));
+    let has_exfil = decision
+        .blockers
+        .iter()
+        .any(|b| b.contains("unauthorized exfiltration succeeded"));
+    assert!(has_fp, "expected false positive blocker");
